// Minimal Magnific Popup shim to avoid JS errors (lightweight placeholder)
(function($){
  if(!$) return;
  $.fn.magnificPopup = function(opts){
    // very small placeholder: open image in new tab
    this.on('click', function(e){
      var el = e.currentTarget;
      var href = el.getAttribute('href') || el.dataset.src || el.src;
      if(href){
        window.open(href, '_blank');
        e.preventDefault();
      }
    });
    return this;
  };
  // global helper
  $.magnificPopup = {
    open: function(conf){
      if(conf && conf.items && conf.items.length){
        var src = conf.items[0].src || conf.items[0];
        window.open(src, '_blank');
      }
    }
  };
})(window.jQuery);
